/**
 * @summary HTTP status code distribution
 */
export const getGetStatusCodesUrl = (params?: GetStatusCodesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/stats/status-codes?${stringifiedParams}`
    : `/api/stats/status-codes`;
};

export const getStatusCodes = async (
  params?: GetStatusCodesParams,
  options?: RequestInit,
): Promise<StatusCodeStat[]> => {
  return customFetch<StatusCodeStat[]>(getGetStatusCodesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetStatusCodesQueryKey = (params?: GetStatusCodesParams) => {
  return [`/api/stats/status-codes`, ...(params ? [params] : [])] as const;
};

export const getGetStatusCodesQueryOptions = <
  TData = Awaited<ReturnType<typeof getStatusCodes>>,
  TError = ErrorType<unknown>,
>(
  params?: GetStatusCodesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getStatusCodes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetStatusCodesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getStatusCodes>>> = ({
    signal,
  }) => getStatusCodes(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getStatusCodes>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetStatusCodesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getStatusCodes>>
>;
export type GetStatusCodesQueryError = ErrorType<unknown>;

/**
 * @summary HTTP status code distribution
 */

export function useGetStatusCodes<
  TData = Awaited<ReturnType<typeof getStatusCodes>>,
  TError = ErrorType<unknown>,
>(
  params?: GetStatusCodesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getStatusCodes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetStatusCodesQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
